def sanitize_for_logging(data: dict) -> dict:
    """Remove or mask sensitive fields before logging."""
    sensitive_fields = {
        'card_number', 'cvv', 'password', 'secret', 'token',
        'account_number', 'routing_number', 'ssn', 'credit_card',
        'pan', 'expiry', 'exp_date', 'security_code', 'api_key',
        'authorization', 'signature'
    }
    sanitized = {}
